// Function: calculateDiscountedPrice
// Parameters: originalPrice (number), discountPercent (number)
// Return type: number (the final price after discount)
function calculateDiscountedPrice(
  originalPrice: number,
  discountPercent: number
): number {
  // Calculate the discount amount
  const discountAmount: number = originalPrice * (discountPercent / 100);
  // Subtract discount from original to get final price
  const finalPrice: number = originalPrice - discountAmount;
  // Return the calculated value
  return finalPrice;
}
// Calling the function with a $50 item at 20% off
const salePrice: number = calculateDiscountedPrice(50, 20);
console.log('Sale price:', salePrice);
// Expected: Sale price: 40
